2643 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
2644                                                FPClassTest DemandedMask,
2645                                                KnownFPClass &Known,
2646                                                unsigned Depth) {
2647   Use &U = I->getOperandUse(OpNo);
2648   Value *V = U.get();
2649   Type *VTy = V->getType();
2650 
2651   if (DemandedMask == fcNone) {
2652     if (isa<UndefValue>(V))
2653       return false;
2654     replaceUse(U, PoisonValue::get(VTy));
2655     return true;
2656   }
2657 
2658   // Handle constant
2659   Instruction *VInst = dyn_cast<Instruction>(V);
2660   if (!VInst) {
2661     // Handle constants and arguments
2662     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
2663 
2664     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
2665     if (ValidResults == fcNone) {
2666       if (isa<UndefValue>(V))
2667         return false;
2668       replaceUse(U, PoisonValue::get(VTy));
2669       return true;
2670     }
2671 
2672     // Do not try to replace values which are already constants (unless we are
2673     // folding to poison). Doing so could promote poison elements to non-poison
2674     // constants.
2675     if (isa<Constant>(V))
2676       return false;
2677 
2678     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
2679     if (!FoldedToConst || FoldedToConst == V)
2680       return false;
2681 
2682     replaceUse(U, FoldedToConst);
2683     return true;
2684   }
2685 
2686   if (Depth == MaxAnalysisRecursionDepth)
2687     return false;
2688 
2689   Value *NewVal;
2690 
2691   if (VInst->hasOneUse()) {
2692     // If the instruction has one use, we can directly simplify it.
2693     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
2694   } else {
2695     // If there are multiple uses of this instruction, then we can simplify
2696     // VInst to some other value, but not modify the instruction.
2697     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
2698                                                 Depth);
2699   }
2700 
2701   if (!NewVal)
2702     return false;
2703   if (Instruction *OpInst = dyn_cast<Instruction>(U))
2704     salvageDebugInfo(*OpInst);
2705 
2706   replaceUse(U, NewVal);
2707   return true;
2708 }
