152   void knownNot(FPClassTest RuleOut) {
153     KnownFPClasses = KnownFPClasses & ~RuleOut;
154     if (isKnownNever(fcNan) && !SignBit) {
155       if (isKnownNever(fcNegative))
156         SignBit = false;
157       else if (isKnownNever(fcPositive))
